import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"菲纳斯特之戒","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/菲纳斯特之戒.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/菲纳斯特之戒.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/菲纳斯特之戒.md"};function _(l,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"菲纳斯特之戒",tabindex:"-1"},[s("菲纳斯特之戒 "),e("a",{class:"header-anchor",href:"#菲纳斯特之戒","aria-label":'Permalink to "菲纳斯特之戒"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),o('<h1 id="菲纳斯特之戒-1" tabindex="-1">菲纳斯特之戒 <a class="header-anchor" href="#菲纳斯特之戒-1" aria-label="Permalink to &quot;菲纳斯特之戒&quot;">​</a></h1><p>菲纳斯特之戒<br> 占据戒指位<br> D+1000<br> 魔幻本质<br> 菲纳斯特之戒是数百年前，一位极需良好防御来面对自己冒险生涯的人打造出来的。多亏了这枚戒指，菲纳斯特活了数百年，自那之后戒指不断易主。戒指可提高佩戴者面对伤害的整体抗性，并赋予完全免疫毒素、咒法和闪电的能力。不过，菲纳斯特非常狡猾，据说他给戒指施了诅咒，戒指最终会从持有者手上消失，返回另一处安息之所，除了菲纳斯特本人，戒指不愿意待在任何人身边......<br> 当然，所谓的传言是假的，这枚戒指实际上不愿意待在任何人身边， 菲纳斯特之戒是被码头鼠施加了印记以防止丢失，这些老鼠可以定位这枚戒指，并会不择手段的将这杀死胆敢偷窃戒指的人，并在拿回后供奉在自己地下的数百个的圣堂里（然后疏于防守），而菲纳斯特也是被码头鼠杀害的，这才是菲纳斯特之戒不断易主的真相，而菲纳斯特之戒的真名和创造者已经不可考证。</p><p>效果：这枚戒指可以提供多种抗力以保护持有者，这种保护甚至延伸到了寿命这一层次，菲纳斯特之戒将确保持有者不再衰老，永恒强健。这是C级的【免疫衰老】效果和免疫C级的【毒素】效果，于此同时，每轮一次，持有这枚戒指的生物，在面对D级及以下的【魔力】推动的法术效果时，可免疫该法术伤害之外的法术效果，特殊的是，在面对的时魔力推动的，造成电击伤害的法术时，将额外获得4点电击抗力。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
